'use client';

import Image from 'next/image';
import type { Exhibit } from '@/types';
import { X } from 'lucide-react';
import { VerifiedBadge } from '@/components/shared/VerifiedBadge';

type ExhibitModalProps = {
  exhibit: Exhibit | null;
  onClose: () => void;
};

export function ExhibitModal({ exhibit, onClose }: ExhibitModalProps) {
  if (!exhibit) return null;

  return (
    <div className="fixed inset-0 z-[70] flex items-center justify-center bg-black/70 px-4 py-6 backdrop-blur-sm" role="dialog" aria-modal="true">
      <div className="relative w-full max-w-3xl overflow-hidden rounded-[2rem] border border-white/10 bg-museum.card shadow-museum">
        <button
          type="button"
          onClick={onClose}
          className="absolute right-4 top-4 z-10 rounded-full border border-white/10 bg-black/30 p-2 text-white transition hover:bg-black/50"
          aria-label="Đóng cửa sổ hiện vật"
        >
          <X className="h-5 w-5" />
        </button>

        <div className="grid gap-0 md:grid-cols-[0.95fr_1.05fr]">
          <div className="relative min-h-[260px]">
            <Image src={exhibit.image} alt={exhibit.title} fill className="object-cover" />
          </div>
          <div className="space-y-5 p-6 md:p-8">
            <div className="flex flex-wrap items-center gap-3">
              <span className="rounded-full border border-museum.accent/20 bg-museum.accent/10 px-3 py-1 text-xs uppercase tracking-[0.24em] text-museum.accent">
                {exhibit.room}
              </span>
              {exhibit.verified ? <VerifiedBadge /> : null}
            </div>

            <div>
              <h3 className="text-2xl font-semibold text-white md:text-3xl">{exhibit.title}</h3>
              <p className="mt-3 text-base leading-7 text-stone-300">{exhibit.summary}</p>
            </div>

            <div className="rounded-3xl border border-white/10 bg-black/20 p-5">
              <p className="text-sm leading-7 text-stone-200">{exhibit.detail}</p>
            </div>

            <div className="grid gap-3 sm:grid-cols-2">
              <div className="rounded-2xl border border-white/10 bg-white/5 p-4 text-sm text-stone-300">
                <div className="mb-1 text-xs uppercase tracking-[0.22em] text-stone-400">Loại hiện vật</div>
                <div className="font-medium text-white">{exhibit.type}</div>
              </div>
              <div className="rounded-2xl border border-white/10 bg-white/5 p-4 text-sm text-stone-300">
                <div className="mb-1 text-xs uppercase tracking-[0.22em] text-stone-400">Mục đích</div>
                <div className="font-medium text-white">Popup / ảnh / mô tả / media liên kết</div>
              </div>
            </div>

            {exhibit.sourceLinks?.length ? (
              <div>
                <div className="mb-3 text-xs uppercase tracking-[0.22em] text-stone-400">Nguồn kiểm chứng</div>
                <div className="flex flex-wrap gap-2">
                  {exhibit.sourceLinks.map((source) => (
                    <a
                      key={source.href}
                      href={source.href}
                      target="_blank"
                      rel="noreferrer"
                      className="rounded-full border border-white/10 bg-white/5 px-3 py-1.5 text-xs text-stone-200 transition hover:border-museum.accent/40 hover:text-white"
                    >
                      {source.label}
                    </a>
                  ))}
                </div>
              </div>
            ) : null}
          </div>
        </div>
      </div>
    </div>
  );
}
